// src/pages/Payments.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";

const Payments = () => {
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(true);

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    const fetchPayments = async () => {
      try {
        const res = await axios.get("http://localhost:5000/api/payments/my", {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setPayments(res.data.payments);
        setLoading(false);
      } catch (err) {
        console.error(err);
        setLoading(false);
      }
    };

    fetchPayments();
  }, [user.token]);

  if (loading) return <p className="loading-text">Loading payments...</p>;

  return (
    <div className="container">
      <h2>My Payments</h2>
      {payments.length === 0 ? (
        <p>You have no payments yet.</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>Event</th>
              <th>Booking Tickets</th>
              <th>Amount</th>
              <th>Status</th>
              <th>Payment Method</th>
            </tr>
          </thead>
          <tbody>
            {payments.map((p) => (
              <tr key={p._id}>
                <td>{p.booking.event.name}</td>
                <td>{p.booking.numberOfTickets}</td>
                <td>${p.amount}</td>
                <td>{p.status}</td>
                <td>{p.paymentMethod}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default Payments;
